@media print {
    @page {
        size: 100mm 50mm;
        margin: 0;
    }
}

*{
    margin:0;
    padding:0;
    /*box-sizing:border-box;*/
    font-weight:bold !important;
}

body{
    margin:0;
    padding:0;
}

.print-format{
    padding:0 !important;
}

/* ONE ROW */
.wrapper{
    width:100mm;
    height:50mm;
    display:flex;
    flex-direction:row;
    page-break-inside:avoid;
}

/* SINGLE LABEL = 50x38 */
.label{
    width:50mm;
    height:38mm;
    padding:2mm 2mm 1mm 2mm;
    overflow:hidden;
}

/* TEXT LEFT SIDE */
.details-block{
    width:100%;
    text-align:left !important;
    font-size:10px;
    line-height:1.2;
    font-family:Arial, sans-serif;
    font-weight:bold;
    padding-left:1mm;
}

/* LABEL TITLES */
.boldtext{
    font-weight:900 !important;
}

/* BARCODE AREA */
.barcode-container{
    width:100%;
    text-align:center;
    margin-top:1mm;
    border:none !important;
    outline:none !important;
    box-shadow:none !important;
    background:transparent !important;
}

/* BARCODE IMAGE */
.barcode-container img{
    width:44mm;
    height:11mm;
    display:block;
    margin:0 auto;
    object-fit:fill;

    border:none !important;
    outline:none !important;
    box-shadow:none !important;
    background:transparent !important;
}
svg{
    border:none !important;
    outline:none !important;
    box-shadow:none !important;
}
/* RWG TEXT */
.bottom-text{
    text-align:center;
    font-size:9px;
    margin-top:1px;
    font-weight:900;
}

.secret-code{
    text-align:center;
    font-size:9px;
    font-weight:900;
    margin-top:1px;
    letter-spacing:1px;
}

