{% set all_serials = [] %}

{% for item in doc.items %}
    {% if item.custom_generated_serials %}

        {% set serial_lines = item.custom_generated_serials.strip().split('\n') %}

        {% for serial in serial_lines %}

            {% if serial|trim %}

                {% set _ = all_serials.append({
                    "serial": serial|trim,
                    "item": item
                }) %}

            {% endif %}

        {% endfor %}

    {% endif %}
{% endfor %}


{% for data in all_serials %}

    {% set item = frappe.get_doc("Item", data.item.item_code) %}

    <div class="wrapper">

        <!-- LEFT LABEL -->
        <div class="label">

            <div class="details-block">
                 {% set product_name = "" %}

                {% if item.custom_departments %}
                  {% set groups = frappe.get_all(
                      "Item Group",
                      filters={
                          "name": item.custom_departments,
                          "custom_is_departmnent": 1
                      },
                      fields=["item_group_name"],
                      limit=1
                  ) %}

                  {% if groups %}
                    {% set product_name = groups[0].item_group_name %}
                  {% endif %}
                {% endif %}
                {{ item.custom_block or "" }}<br>

                <span class="boldtext">ITEM NO:</span>
                {{ item.item_code }}<br>

                {{ item.brand or "" }}<br>

                <span class="boldtext">PRODUCT:</span>
                {{ product_name or item.product_name or "" }}<br>

                {{ item.custom_size or "" }}

            </div>

            <div class="barcode-container">

                <img
                    src="{{ generate_custom_barcode(item.custom_barcode_code) }}"
                    style="image-rendering:pixelated;"
                >

                <div class="bottom-text">
                    ***RWG***
                </div>
{% set mrp_map = {
    "1":"B",
    "2":"L",
    "3":"A",
    "4":"C",
    "5":"K",
    "6":"H",
